CREATE TABLE CLAIMS_HISTORY (
    CLAIM_ID VARCHAR(20),
    CLAIM_STATUS VARCHAR(20)
);

CREATE TABLE CUSTOMER_MASTER (
    CUSTOMER_ID VARCHAR(20),
    CUSTOMER_NAME VARCHAR(100)
);

//JOB001   JOB (ACCT),'CODEGENOME DAILY BATCH',CLASS=A,MSGCLASS=X,
//             NOTIFY=&SYSUID
//*
//* STEP 1: SORT EMPLOYEE INPUT FILE
//*
//SORTSTEP EXEC PGM=SORT
//SORTIN   DD DSN=EMP.RAW.INPUT.FILE,DISP=SHR
//SORTOUT  DD DSN=EMP.INPUT.FILE,DISP=(NEW,CATLG,DELETE)
//SYSOUT   DD SYSOUT=*
//SYSIN    DD *
  SORT FIELDS=(1,5,CH,A)
/*
//*
//* STEP 2: EXECUTE PAYROLL PROGRAM
//*
//PAYSTEP  EXEC PGM=PAYROLL
//STEPLIB  DD DSN=PAYROLL.LOADLIB,DISP=SHR
//EMPIN    DD DSN=EMP.INPUT.FILE,DISP=SHR
//PAYOUT   DD DSN=EMP.OUTPUT.FILE,DISP=(NEW,CATLG,DELETE)
//SYSOUT   DD SYSOUT=*
//SYSIN    DD DUMMY
//*
//* STEP 3: EXECUTE CUSTOMER RISK PROGRAM
//*
//CUSTSTEP EXEC PGM=CUSTOMER
//STEPLIB  DD DSN=CUSTOMER.LOADLIB,DISP=SHR
//CUSTIN   DD DSN=CUSTOMER.INPUT.FILE,DISP=SHR
//SYSOUT   DD SYSOUT=*
//SYSIN    DD DUMMY
//*
//* STEP 4: GENERATE DAILY REPORT
//*
//RPTSTEP  EXEC PGM=REPORTGEN
//REPORTIN DD DSN=EMP.OUTPUT.FILE,DISP=SHR
//REPORT   DD DSN=PAYROLL.DAILY.REPORT,DISP=(NEW,CATLG,DELETE)
//SYSOUT   DD SYSOUT=*

//MONTHEND JOB (FIN),'MONTH END'
//STEP01 EXEC PGM=INTCALC
//STEP02 EXEC PGM=PREMIUM

//NIGHTLY JOB (ACCT),'NIGHT BATCH'
//STEP01 EXEC PGM=ACCTOPEN
//STEP02 EXEC PGM=FUNDSXFER
//STEP03 EXEC PGM=RECON

CREATE TABLE PAYMENT_AUDIT (
    PAYMENT_ID VARCHAR(20),
    STATUS VARCHAR(20)
);

//YEARCLOSE JOB (FIN),'YEAR CLOSE'
//STEP01 EXEC PGM=RECON
//STEP02 EXEC PGM=CLAIMPAY
